const data = $input.first().json;

// Adjust field names if the API response differs
const listings = data.items ?? data.results ?? data.data ?? [];

// Build a map of id -> listing for easy lookup
const current = {};
for (const item of listings) {
  const id = String(item.id ?? item.objectId ?? item.externalId);
  current[id] = item;
}

// Retrieve previously seen IDs from workflow static data
const staticData = $getWorkflowStaticData('global');
const seen = new Set(staticData.seenIds ?? []);

// Find new listings
const newListings = Object.entries(current)
  .filter(([id]) => !seen.has(id))
  .map(([id, item]) => ({ id, item }));

// Persist updated seen set (keep last 500 to avoid unbounded growth)
const allIds = [...seen, ...newListings.map(l => l.id)];
staticData.seenIds = allIds.slice(-500);

if (newListings.length === 0) return [];

return newListings.map(({ id, item }) => ({
  json: {
    id,
    title: item.title ?? item.name ?? `Wohnung ${id}`,
    price: item.rent ?? item.price ?? item.totalRent ?? '?',
    size: item.livingArea ?? item.area ?? item.size ?? '?',
    rooms: item.numberOfRooms ?? item.rooms ?? '?',
    floor: item.floor ?? '',
    address: [item.street, item.houseNumber, item.zipCode, item.city]
      .filter(Boolean).join(' '),
    url: `https://www.deutsche-wohnen.com/mieten/mietangebote/${id}`,
  }
}));
